import{_ as o,C as n,o as l,c as s,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Estonia","description":"Immigration pathways and relocation guide for Estonia","frontmatter":{"layout":"doc","title":"Moving to Estonia","description":"Immigration pathways and relocation guide for Estonia"},"headers":[],"relativePath":"europe/estonia/moving-there.md","filePath":"europe/estonia/moving-there.md","lastUpdated":null}'),h={name:"europe/estonia/moving-there.md"};function g(u,e,c,m,p,f){const t=n("Badge");return l(),s("div",null,[i(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[r("EU: Free Movement",-1)])]),_:1}),i(t,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[r("Digital Nomad Visa (2022)",-1)])]),_:1}),i(t,{variant:"green"},{default:a(()=>[...e[2]||(e[2]=[r("e-Residency Program",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="moving-to-estonia" tabindex="-1">Moving to Estonia <a class="header-anchor" href="#moving-to-estonia" aria-label="Permalink to &quot;Moving to Estonia&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register your place of residence with the Population Register (Rahvastikuregister)</li><li><strong>Right to work</strong>: Automatic, no work permit needed</li><li><strong>EU citizen certificate</strong>: Obtain from the Police and Border Guard Board</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Estonian employer)</li><li>Business visa (for entrepreneurs)</li><li>Family reunification</li><li>Digital Nomad Visa</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Estonian employer</td><td>Up to 2 years, renewable</td></tr><tr><td>Digital Nomad Visa</td><td>Remote work, min income ~€4,500/month</td><td>Up to 1 year</td></tr><tr><td>Start-up Visa</td><td>Innovative business, approved by committee</td><td>Up to 2 years</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Estonian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>e-Residency</td><td>Digital entrepreneur (no physical residency)</td><td>5 years (renewable)</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Estonia introduced the <strong>Digital Nomad Visa</strong> in 2022:</p><ul><li>For remote workers employed outside Estonia</li><li>Minimum income: ~€4,500/month (gross)</li><li>Valid for up to 1 year</li><li>Can apply from abroad or while in Estonia on a tourist visa</li><li>Covers family members</li><li>Fast processing (15-30 days)</li></ul><h3 id="e-residency" tabindex="-1">e-Residency <a class="header-anchor" href="#e-residency" aria-label="Permalink to &quot;e-Residency&quot;">​</a></h3><p>Estonia&#39;s unique <strong>e-Residency program</strong> allows digital entrepreneurs to:</p><ul><li>Register an EU-based company remotely</li><li>Access Estonian e-services and digital banking</li><li>Use the digital ID card for signing documents</li><li>Does NOT confer physical residency or right to live in Estonia</li><li>Excellent for digital nomads who want an EU business presence</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply well in advance (1-3 months processing)</li><li>[ ] <strong>Healthcare</strong>: Register with Estonian Health Insurance Fund</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter</li><li>[ ] <strong>Banking</strong>: Consider LHV, Swedbank, or SEB (e-residents can open accounts remotely)</li><li>[ ] <strong>Housing</strong>: Research rental market (kv.ee, city24.ee)</li><li>[ ] <strong>Language</strong>: Basic Estonian helpful; English widely spoken in Tallinn</li><li>[ ] <strong>e-Residency</strong>: Apply if relevant (separate from physical residency)</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register residence with Population Register (within 3 months for EU)</li><li>[ ] Apply for Estonian ID card (isikutunnistus) or digital ID</li><li>[ ] Register with the Health Insurance Fund (Haigekassa)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Telia, Elisa, Tele2)</li><li>[ ] Connect with LGBTQ+ community (Trans in Estonia, LGBTQ+ association)</li><li>[ ] Register for healthcare with a GP (perearst)</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Low to moderate</strong> compared to Western Europe</li><li>Monthly rent (1-bed): €400-800 (Tallinn), €300-600 (Tartu)</li><li>Monthly groceries: €300-500</li><li>Public transport: €30/month (Tallinn free for residents)</li><li>Dining out: €10-20 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Tallinn</strong></td><td>Good (growing scene)</td><td>Best (PERH)</td></tr><tr><td><strong>Tartu</strong></td><td>Moderate</td><td>Good (University Hospital)</td></tr><tr><td><strong>Pärnu</strong></td><td>Limited</td><td>Limited</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to -15°C), limited daylight (6 hours)</li><li><strong>Summers</strong>: Mild (15°C to 25°C), white nights</li><li><strong>Best time to arrive</strong>: Late spring/summer (May-September)</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Estonian (Uralic, not Indo-European — challenging)</li><li>Russian: Widely spoken, especially among older generations</li><li>English: Widely spoken in Tallinn and among younger people</li><li>Free Estonian language courses available for immigrants</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.politsei.ee/" target="_blank" rel="noreferrer">Police and Border Guard Board (PPA)</a></li><li><a href="https://www.haigekassa.ee/" target="_blank" rel="noreferrer">Estonian Health Insurance Fund</a></li><li><a href="https://e-resident.gov.ee/" target="_blank" rel="noreferrer">e-Residency Program</a></li><li><a href="https://www.workinestonia.com/" target="_blank" rel="noreferrer">Work in Estonia</a></li><li><a href="https://www.settleinestonia.ee/" target="_blank" rel="noreferrer">Settle in Estonia</a></li><li><a href="https://trans.ee/" target="_blank" rel="noreferrer">Trans in Estonia</a></li></ul>',30))])}const k=o(h,[["render",g]]);export{b as __pageData,k as default};
